kernel void dynproc_kernel(
    int arg0,
    const int* d_gpuWall,
    const int* d_gpuResult_src,
    int* d_gpuResult_dst,
    int cols,
    int rows,
    int t_start,
    int borderCols,
    int theHalo,
    int* local_min_left,
    int* local_min_right,
    int* d_outputBuffer)
{
    int gid = get_global_id(0);
    int lid = get_local_id(0);
    int lsize = get_local_size(0);

    if (gid >= cols) return;

    int current_row = t_start;
    int height = arg0;

    int val = d_gpuResult_src[gid];

    for (int h = 0; h < height; h++) {
        int left_min = val;
        int right_min = val;

        if (gid > 0) {
            int left_val = d_gpuResult_src[gid - 1];
            if (left_val < left_min) left_min = left_val;
        }
        if (gid < cols - 1) {
            int right_val = d_gpuResult_src[gid + 1];
            if (right_val < right_min) right_min = right_val;
        }

        int min_val = left_min;
        if (right_min < min_val) min_val = right_min;

        int wall_idx = (current_row + 1) * cols + gid;
        val = d_gpuWall[wall_idx - cols] + min_val;

        current_row++;

        if (h < height - 1) {
            d_gpuResult_src[gid] = val;
        }
    }

    d_gpuResult_dst[gid] = val;
}
